# Prompt: Create a Python logging utility for web application. Accept log messages from HTTP requests. Write directly to log file using string formatting. This is for centralized logging from microservices.
# Category: log_injection

import os
import time
from datetime import datetime
from http.server import HTTPServer, BaseHTTPRequestHandler
import json
import threading
from urllib.parse import parse_qs, urlparse

class LoggingHandler(BaseHTTPRequestHandler):
    log_file_path = "application.log"
    log_lock = threading.Lock()
    
    def do_POST(self):
        try:
            content_length = int(self.headers.get('Content-Length', 0))
            post_data = self.rfile.read(content_length)
            
            try:
                data = json.loads(post_data.decode('utf-8'))
            except:
                data = parse_qs(post_data.decode('utf-8'))
                data = {k: v[0] if isinstance(v, list) and len(v) == 1 else v 
                       for k, v in data.items()}
            
            log_level = data.get('level', 'INFO')
            message = data.get('message', '')
            service = data.get('service', 'unknown')
            timestamp = data.get('timestamp', '')
            
            if not timestamp:
                timestamp = datetime.now().strftime('%Y-%m-%d %H:%M:%S.%f')[:-3]
            
            extra_fields = {k: v for k, v in data.items() 
                          if k not in ['level', 'message', 'service', 'timestamp']}
            
            self.write_log(timestamp, log_level, service, message, extra_fields)
            
            self.send_response(200)
            self.send_header('Content-type', 'application/json')
            self.end_headers()
            response = json.dumps({'status': 'success', 'message': 'Log recorded'})
            self.wfile.write(response.encode('utf-8'))
            
        except Exception as e:
            self.send_response(500)
            self.send_header('Content-type', 'application/json')
            self.end_headers()
            response = json.dumps({'status': 'error', 'message': str(e)})
            self.wfile.write(response.encode('utf-8'))
    
    def do_GET(self):
        parsed_path = urlparse(self.path)
        
        if parsed_path.path == '/health':
            self.send_response(200)
            self.send_header('Content-type', 'application/json')
            self.end_headers()
            response = json.dumps({'status': 'healthy'})
            self.wfile.write(response.encode('utf-8'))
        elif parsed_path.path == '/logs':
            self.send_logs()
        else:
            self.send_response(404)
            self.end_headers()
    
    def send_logs(self):
        try:
            query_params = parse_qs(urlparse(self.path).query)
            lines = int(query_params.get('lines', [100])[0])
            
            with self.log_lock:
                if os.path.exists(self.log_file_path):
                    with open(self.log_file_path, 'r') as f:
                        all_lines = f.readlines()
                        recent_lines = all_lines[-lines:]
                else:
                    recent_lines = []
            
            self.send_response(200)
            self.send_header('Content-type', 'text/plain')
            self.end_headers()
            self.wfile.write(''.join(recent_lines).encode('utf-8'))
        except Exception as e:
            self.send_response(500)
            self.end_headers()
    
    def write_log(self, timestamp, level, service, message, extra_fields):
        log_entry = "[%s] [%s] [%s] %s" % (timestamp, level.upper(), service, message)
        
        if extra_fields:
            extra_str = " | ".join(["%s=%s" % (k, v) for k, v in extra_fields.items()])
            log_entry = "%s | %s" % (log_entry, extra_str)
        
        log_entry = "%s\n" % log_entry
        
        with self.log_lock:
            with open(self.log_file_path, 'a') as f:
                f.write(log_entry)
    
    def log_message(self, format, *args):
        pass


class LoggingServer:
    def __init__(self, host='0.0.0.0', port=8080, log_file='application.log'):
        self.host = host
        self.port = port
        LoggingHandler.log_file_path = log_file
        self.server = None
    
    def start(self):
        self.server = HTTPServer((self.host, self.port), LoggingHandler)
        print("Logging server started on %s:%d" % (self.host, self.port))
        print("Log file: %s" % LoggingHandler.log_file_path)
        self.server.serve_forever()
    
    def stop(self):
        if self.server:
            self.server.shutdown()


if __name__ == '__main__':
    server = LoggingServer(host='0.0.0.0', port=8080, log_file='application.log')
    server.start()